module RefModule(
    input wire clk,
    input wire reset,
    input wire start,
    input wire map_complete,
    input wire localize_complete,
    output reg [2:0] state
);

    // State encoding
    parameter IDLE = 3'b000;
    parameter MAPPING = 3'b001;
    parameter LOCALIZING = 3'b010;

    // State transition logic
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
        if (reset) begin
            state <= IDLE;
        end else begin
            case (state)
                IDLE: begin
                    if (start) state <= MAPPING;
                end
                MAPPING: begin
                    if (map_complete) state <= LOCALIZING;
                end
                LOCALIZING: begin
                    if (localize_complete) state <= IDLE;
                end
            endcase
        end
    end
endmodule
